#include<bits/stdc++.h>
using namespace std;
struct node {
	int x;
	int y;

};
struct cmp {
	bool operator()(node a, node b) {
		return a.x>b.x;
	}
};
int n, m;
bool v[5005];
priority_queue<node,vector<node>,cmp> q;
vector<node> a[5005];
int prim(int ans, int x, int jian) {
    v[x]=1;
	if (ans == n) return jian;
	for (int i = 0; i < a[x].size(); i++) {
		q.push(a[x][i]);
	}
	while (!q.empty()) {
		node now = q.top();
		q.pop();
		if (!v[now.y]) {
			return prim(ans + 1, now.y, jian + now.x);
		}

	}
	return -1;
}

int main() {
	//memset(a, 127, sizeof(a));
    ios_base::sync_with_stdio(false);
	cin>>n>>m;
    int shou=0;
	for(int i=1;i<=m;i++){
		int x,y,z;
		cin>>x>>y>>z;
        shou=x;
        a[x].push_back({z, y});
        a[y].push_back({z, x});

	}
	long long annnns=prim(1,1,0);
	if(annnns==-1) cout<<"orz";
	else cout<<annnns;
	return 0;
}
